function.body:
p_record_id VARCHAR(60);
    p_docAction VARCHAR(60);
    p_user VARCHAR(60);
    v_ResultStr VARCHAR2(2000):='';
    Cur_Params RECORD;
    rInout RECORD;
    rAtribute RECORD;
    vDescription VARCHAR(255):='';
    vLineBreak TEXT:='
';
BEGIN

    FOR Cur_Params IN (
        SELECT *
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = p_ep_instance
    ) LOOP
        IF cur_params.parametername = 'DocAction' THEN
            p_docaction := Cur_Params.p_string;
        ELSIF (cur_params.parametername = 'Record_ID') THEN
            p_record_id := cur_params.p_string;
        ELSIF (cur_params.parametername = 'User') THEN
            p_user := cur_params.p_string;
        END IF;
    END LOOP;


    FOR rAtribute IN (
        select mio.docstatus, ma.ismandatory, mp.m_product_id ,mp.name, miol.M_AttributeSetInstance_ID, mau.M_Attribute_id, miol.line
        from m_inout mio
        join M_InOutLine miol on mio.m_inout_id = miol.m_inout_id
        join M_Product mp on miol.m_product_id = mp.m_product_id
        join M_AttributeSet mas on mas.M_AttributeSet_id = mp.M_AttributeSet_id 
        join M_AttributeUse mau on mau.M_AttributeSet_id = mas.M_AttributeSet_id
        join M_Attribute ma on ma.M_Attribute_id = mau.M_Attribute_id
        join c_doctype cdoc on cdoc.c_doctype_id = mio.c_doctype_id
        where mio.MovementType IN ('V-', 'V+') 
        and mio.isLogistic = 'N'
        and cdoc.isreturn = 'N'
    	and mio.m_inout_id = p_record_id
		order by miol.line asc
    ) LOOP
        IF ratribute.docstatus = 'CO' and rAtribute.ismandatory = 'Y' and 
		ratribute.M_AttributeSetInstance_ID IS NULL and ratribute.M_Attribute_id <> '0'
		THEN
			RAISE EXCEPTION '%', 'En la linea ' || ratribute.line || ' el producto '|| 
			ratribute.name  || ' no tiene valor de atributos.';
        END IF;
    END LOOP;


    EXCEPTION WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('ssia_mandatory_atribute exception: '|| v_ResultStr);
    RAISE;
END SSIA_MANDATORY_ATRIBUTE
